// COT Market Name Mapping
const marketMapping = {
  'EURO FX': 'EURUSD',
  'JAPANESE YEN': 'USDJPY',
  'BRITISH POUND': 'GBPUSD',
  'SWISS FRANC': 'USDCHF',
  'CANADIAN DOLLAR': 'USDCAD',
  'AUSTRALIAN DOLLAR': 'AUDUSD',
  'S&P 500 STOCK INDEX': 'ES',
  'NASDAQ-100 STOCK INDEX': 'NQ',
  'CRUDE OIL, LIGHT SWEET': 'CL',
  'GOLD': 'XAUUSD',
  'SILVER': 'XAGUSD',
  'BITCOIN': 'BTC'
};

const targetMarkets = Object.keys(marketMapping);

// Get the input data
const items = $input.all();
const rawData = items[0].json;

// CFTC API returns results array
const records = rawData.results || rawData || [];

// Filter and map records
const filteredRecords = records
  .filter(record => {
    const marketName = record.market_name || '';
    return targetMarkets.includes(marketName);
  })
  .map(record => {
    const marketName = record.market_name || '';
    return {
      symbol: marketMapping[marketName],
      market_name: marketName,
      report_date: record.report_date,
      long_commercial: parseInt(record.long_commercial) || 0,
      short_commercial: parseInt(record.short_commercial) || 0,
      long_noncommercial: parseInt(record.long_noncommercial) || 0,
      short_noncommercial: parseInt(record.short_noncommercial) || 0,
      net_commercial: (parseInt(record.long_commercial) || 0) - (parseInt(record.short_commercial) || 0),
      net_noncommercial: (parseInt(record.long_noncommercial) || 0) - (parseInt(record.short_noncommercial) || 0)
    };
  });

// Group by symbol and get most recent
const latestBySymbol = {};
filteredRecords.forEach(record => {
  const existing = latestBySymbol[record.symbol];
  if (!existing || new Date(record.report_date) > new Date(existing.report_date)) {
    latestBySymbol[record.symbol] = record;
  }
});

// Return as array
const result = Object.values(latestBySymbol);

return result.map(item => ({ json: item }));

// Load cached history for comparison
const fs = require('fs');
const path = require('path');

const cacheDir = '/data/cache';
const historyPath = path.join(cacheDir, 'cot_history.json');

let history = {};
try {
  if (fs.existsSync(historyPath)) {
    const historyData = fs.readFileSync(historyPath, 'utf8');
    history = JSON.parse(historyData);
  }
} catch (e) {
  // No history yet, will be created
}

// Get current week data
const currentData = $input.all();
const currentWeekDate = new Date().toISOString().split('T')[0];

const results = [];

for (const item of currentData) {
  const record = item.json;
  const symbol = record.symbol;

  // Get previous week data for comparison
  const prevWeek = history[symbol] || null;
  const prevNetCommercial = prevWeek ? prevWeek.net_commercial : 0;
  const prevNetNonCommercial = prevWeek ? prevWeek.net_noncommercial : 0;

  // Calculate weekly change
  const cambioSemanalCommercial = record.net_commercial - prevNetCommercial;
  const cambioSemanalNonCommercial = record.net_noncommercial - prevNetNonCommercial;

  // Calculate total open interest for percentage calculations
  const totalLong = record.long_commercial + record.long_noncommercial;
  const totalShort = record.short_commercial + record.short_noncommercial;
  const totalOpenInterest = totalLong + totalShort;

  // Institutional bias: based on non-commercial net position as % of open interest
  let sesgoInstitucional = 'NEUTRAL';
  if (totalOpenInterest > 0) {
    const nonCommercialPct = (record.net_noncommercial / totalOpenInterest) * 100;
    if (nonCommercialPct > 10) {
      sesgoInstitucional = 'LONG';
    } else if (nonCommercialPct < -10) {
      sesgoInstitucional = 'SHORT';
    }
  }

  // Calculate historical percentile
  // We need to track historical values - for now, use prevWeek data if available
  let extremoHistorico = false;
  if (prevWeek && prevWeek.historicalValues && prevWeek.historicalValues.length >= 4) {
    const historicalValues = prevWeek.historicalValues;
    const currentNetNonComm = record.net_noncommercial;

    // Calculate percentile
    const sorted = [...historicalValues].sort((a, b) => a - b);
    const below = sorted.filter(v => v < currentNetNonComm).length;
    const percentile = (below / sorted.length) * 100;

    extremoHistorico = percentile > 80 || percentile < 20;
  }

  // Build result
  const resultRecord = {
    ...record,
    week_date: currentWeekDate,
    cambio_semanal_commercial: cambioSemanalCommercial,
    cambio_semanal_noncommercial: cambioSemanalNonCommercial,
    sesgo_institucional: sesgoInstitucional,
    extremo_historico: extremoHistorico,
    timestamp: new Date().toISOString()
  };

  results.push({ json: resultRecord });
}

return results;

// Format summary report
const items = $input.all();

const currentDate = new Date();
const weekFecha = currentDate.toISOString().split('T')[0];

let summary = `REPORTE COT — Semana ${weekFecha}\n\n`;

const marketEmojis = {
  'EURUSD': '🇪🇺💱',
  'USDJPY': '💴',
  'GBPUSD': '🇬🇧💱',
  'USDCHF': '🇨🇭',
  'USDCAD': '🇨🇦',
  'AUDUSD': '🇦🇺💱',
  'ES': '📊 SP500',
  'NQ': '📈 NASDAQ',
  'CL': '🛢️ Oil',
  'XAUUSD': '🥇 Gold',
  'XAGUSD': '🥈 Silver',
  'BTC': '₿ Bitcoin'
};

for (const item of items) {
  const r = item.json;
  const emoji = marketEmojis[r.symbol] || '📦';

  // Direction indicators
  const direccion = r.sesgo_institucional;
  const dirEmoji = direccion === 'LONG' ? '📈' : direccion === 'SHORT' ? '📉' : '➡️';

  // Change indicators
  const cambioComm = r.cambio_semanal_commercial || 0;
  const cambioEmoji = cambioComm > 0 ? '🔺' : cambioComm < 0 ? '🔻' : '➡️';

  // Extreme warning
  const extremoWarning = r.extremo_historico ? '\n   ⚠️ EXTREMO HISTÓRICO' : '';

  summary += `${emoji} ${r.symbol}: Institucionales ${direccion} ${dirEmoji} neto ${r.net_noncommercial} contratos\n`;
  summary += `   (cambio: ${cambioEmoji} ${Math.abs(cambioComm)} vs semana anterior)${extremoWarning}\n\n`;
}

summary += `\nGenerado: ${new Date().toISOString()}`;

return [{ json: { summary, week_date: weekFecha } }];

// Rotate and store 52-week history
const fs = require('fs');
const path = require('path');

const cacheDir = '/data/cache';
const historyPath = path.join(cacheDir, 'cot_history.json');

// Ensure cache directory exists
if (!fs.existsSync(cacheDir)) {
  fs.mkdirSync(cacheDir, { recursive: true });
}

// Load existing history
let history = {};
try {
  if (fs.existsSync(historyPath)) {
    history = JSON.parse(fs.readFileSync(historyPath, 'utf8'));
  }
} catch (e) {
  history = {};
}

const currentWeekDate = new Date().toISOString().split('T')[0];
const items = $input.all();

// Update history with current week data
for (const item of items) {
  const record = item.json;
  const symbol = record.symbol;

  if (!history[symbol]) {
    history[symbol] = {
      historicalValues: [],
      weeklyData: []
    };
  }

  // Add current net position to historical values
  history[symbol].historicalValues.push(record.net_noncommercial);
  history[symbol].weeklyData.unshift({
    date: currentWeekDate,
    net_commercial: record.net_commercial,
    net_noncommercial: record.net_noncommercial,
    long_commercial: record.long_commercial,
    short_commercial: record.short_commercial,
    long_noncommercial: record.long_noncommercial,
    short_noncommercial: record.short_noncommercial
  });

  // Keep only last 52 weeks
  if (history[symbol].historicalValues.length > 52) {
    history[symbol].historicalValues = history[symbol].historicalValues.slice(-52);
  }
  if (history[symbol].weeklyData.length > 52) {
    history[symbol].weeklyData = history[symbol].weeklyData.slice(0, 52);
  }
}

// Save updated history
fs.writeFileSync(historyPath, JSON.stringify(history, null, 2));

return [{ json: { stored: true, records: items.length, historyPath } }];

// Prepare webhook responses
const fs = require('fs');
const path = require('path');

const cacheDir = '/data/cache';
const latestPath = path.join(cacheDir, 'cot_latest.json');
const summaryPath = path.join(cacheDir, 'cot_summary.txt');

// Return latest data for cot-data webhook
let latestData = null;
try {
  if (fs.existsSync(latestPath)) {
    latestData = JSON.parse(fs.readFileSync(latestPath, 'utf8'));
  }
} catch (e) {
  latestData = { error: 'No data available' };
}

return [{ json: latestData }];

// Prepare summary for cot-latest webhook
const fs = require('fs');
const path = require('path');

const cacheDir = '/data/cache';
const summaryPath = path.join(cacheDir, 'cot_summary.txt');

let summary = 'No summary available';
try {
  if (fs.existsSync(summaryPath)) {
    summary = fs.readFileSync(summaryPath, 'utf8');
  }
} catch (e) {
  // Return default
}

return [{ json: { summary } }];
